        {"title": "编写Appium初始化脚本", "description": "编写Python代码，使用Appium的webdriver初始化一个Android会话，配置Desired Capabilities连接设备。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "Appium框架", "knowledge_point": "初始化会话", "code_template": "from appium import webdriver\n\n# 配置Desired Capabilities\ncaps = {\n\n}\n\n# 初始化driver\n", "solution": "from appium import webdriver\n\ncaps = {\n    'platformName': 'Android',\n    'deviceName': 'emulator-5554',\n    'appPackage': 'com.example.app',\n    'appActivity': '.MainActivity',\n    'automationName': 'UiAutomator2'\n}\n\ndriver = webdriver.Remote('http://localhost:4723/wd/hub', caps)", "hint": "使用webdriver.Remote()连接Appium Server"},
        {"title": "编写Appium元素定位脚本", "description": "编写Python代码，使用Appium通过ID、xpath、class_name三种方式定位元素并获取文本。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "元素定位", "knowledge_point": "多种定位方式", "code_template": "from appium.webdriver.common.by import By\n\n# 通过ID定位\n\n# 通过xpath定位\n\n# 通过class_name定位\n", "solution": "from appium.webdriver.common.by import By\n\n# 通过ID定位\nelement_by_id = driver.find_element(By.ID, 'com.example:id/title')\nprint(element_by_id.text)\n\n# 通过xpath定位\nelement_by_xpath = driver.find_element(By.XPATH, '//android.widget.TextView[@text=\"Hello\"]')\nprint(element_by_xpath.text)\n\n# 通过class_name定位\nelements_by_class = driver.find_elements(By.CLASS_NAME, 'android.widget.Button')\nfor elem in elements_by_class:\n    print(elem.text)", "hint": "使用find_element和By类进行定位"},
        {"title": "编写Appium等待元素脚本", "description": "编写Python代码，使用WebDriverWait实现显式等待，等待元素可点击后再操作。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "元素定位", "knowledge_point": "显式等待", "code_template": "from selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\nfrom appium.webdriver.common.by import By\n\n# 显式等待元素可点击\n", "solution": "from selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\nfrom appium.webdriver.common.by import By\n\n# 等待元素可点击\nwait = WebDriverWait(driver, 10)\nelement = wait.until(\n    EC.element_to_be_clickable((By.ID, 'com.example:id/login_button'))\n)\nelement.click()\nprint('元素已点击')", "hint": "使用WebDriverWait配合expected_conditions"},
        {"title": "编写ADB安装应用脚本", "description": "编写Python代码，使用subprocess模块调用ADB命令安装APK文件。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "ADB命令", "knowledge_point": "安装APK", "code_template": "import subprocess\n\n# 使用ADB安装APK\n", "solution": "import subprocess\n\ndef install_apk(apk_path):\n    result = subprocess.run(\n        ['adb', 'install', '-r', apk_path],\n        capture_output=True,\n        text=True\n    )\n    if result.returncode == 0:\n        print(f'安装成功: {apk_path}')\n    else:\n        print(f'安装失败: {result.stderr}')\n    return result.returncode == 0\n\ninstall_apk('app-release.apk')", "hint": "使用subprocess.run()调用adb install命令"},
        {"title": "编写ADB截屏脚本", "description": "编写Python代码，使用ADB命令截取设备屏幕并保存到本地。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "ADB命令", "knowledge_point": "截屏命令", "code_template": "import subprocess\nimport time\n\n# ADB截屏并拉取到本地\n", "solution": "import subprocess\nimport time\n\ndef adb_screenshot(local_path='screenshot.png'):\n    device_path = '/sdcard/screenshot.png'\n    # 在设备上截屏\n    subprocess.run(['adb', 'shell', 'screencap', '-p', device_path], check=True)\n    # 拉取到本地\n    subprocess.run(['adb', 'pull', device_path, local_path], check=True)\n    # 删除设备上的文件\n    subprocess.run(['adb', 'shell', 'rm', device_path], check=True)\n    print(f'截屏已保存: {local_path}')\n\nadb_screenshot('test_screenshot.png')", "hint": "使用screencap命令截屏，pull命令拉取文件"},
        {"title": "编写Appium滑动操作脚本", "description": "编写Python代码，使用Appium实现屏幕向上滑动和向左滑动操作。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "Appium框架", "knowledge_point": "滑动操作", "code_template": "from appium.webdriver.common.touch_action import TouchAction\n\n# 实现滑动操作\n", "solution": "from appium.webdriver.common.touch_action import TouchAction\n\ndef swipe_up(driver):\n    screen_size = driver.get_window_size()\n    width = screen_size['width']\n    height = screen_size['height']\n    action = TouchAction(driver)\n    action.press(x=width//2, y=height*3//4) \\\n        .wait(ms=500) \\\n        .move_to(x=width//2, y=height//4) \\\n        .release() \\\n        .perform()\n    print('向上滑动完成')\n\ndef swipe_left(driver):\n    screen_size = driver.get_window_size()\n    width = screen_size['width']\n    height = screen_size['height']\n    action = TouchAction(driver)\n    action.press(x=width*3//4, y=height//2) \\\n        .wait(ms=500) \\\n        .move_to(x=width//4, y=height//2) \\\n        .release() \\\n        .perform()\n    print('向左滑动完成')", "hint": "使用TouchAction的press、move_to、release方法"},
        {"title": "编写Appium输入文本脚本", "description": "编写Python代码，使用Appium在输入框中输入文本并点击提交按钮。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "元素定位", "knowledge_point": "输入文本", "code_template": "from appium.webdriver.common.by import By\n\n# 定位输入框并输入文本\n", "solution": "from appium.webdriver.common.by import By\n\n# 定位用户名输入框\nusername_input = driver.find_element(By.ID, 'com.example:id/username')\nusername_input.clear()\nusername_input.send_keys('testuser')\n\n# 定位密码输入框\npassword_input = driver.find_element(By.ID, 'com.example:id/password')\npassword_input.clear()\npassword_input.send_keys('test123')\n\n# 点击登录按钮\nlogin_button = driver.find_element(By.ID, 'com.example:id/login_btn')\nlogin_button.click()\nprint('登录操作完成')", "hint": "使用send_keys()输入文本，click()点击按钮"},
        {"title": "编写ADB获取设备信息脚本", "description": "编写Python代码，使用ADB命令获取Android设备的型号、系统版本、分辨率等信息。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "ADB命令", "knowledge_point": "设备信息", "code_template": "import subprocess\n\n# 获取设备信息\n", "solution": "import subprocess\n\ndef get_device_info():\n    info = {}\n    # 获取设备型号\n    result = subprocess.run(['adb', 'shell', 'getprop', 'ro.product.model'], capture_output=True, text=True)\n    info['model'] = result.stdout.strip()\n    # 获取系统版本\n    result = subprocess.run(['adb', 'shell', 'getprop', 'ro.build.version.release'], capture_output=True, text=True)\n    info['android_version'] = result.stdout.strip()\n    # 获取分辨率\n    result = subprocess.run(['adb', 'shell', 'wm', 'size'], capture_output=True, text=True)\n    info['screen_size'] = result.stdout.strip()\n    # 获取DPI\n    result = subprocess.run(['adb', 'shell', 'wm', 'density'], capture_output=True, text=True)\n    info['density'] = result.stdout.strip()\n    for key, value in info.items():\n        print(f'{key}: {value}')\n    return info\n\nget_device_info()", "hint": "使用getprop获取系统属性"},
        {"title": "编写Appium手势操作脚本", "description": "编写Python代码，使用Appium实现长按和双击手势操作。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "Appium框架", "knowledge_point": "手势操作", "code_template": "from appium.webdriver.common.touch_action import TouchAction\nfrom appium.webdriver.common.by import By\n\n# 长按和双击操作\n", "solution": "from appium.webdriver.common.touch_action import TouchAction\nfrom appium.webdriver.common.by import By\n\ndef long_press_element(driver, element, duration=2000):\n    action = TouchAction(driver)\n    action.long_press(el=element, ms=duration).release().perform()\n    print(f'长按元素 {duration}ms')\n\ndef double_tap_element(driver, element):\n    action = TouchAction(driver)\n    action.tap(el=element, count=2).perform()\n    print('双击元素完成')\n\n# 使用示例\nelement = driver.find_element(By.ID, 'com.example:id/target')\nlong_press_element(driver, element)\ndouble_tap_element(driver, element)", "hint": "使用TouchAction的long_press和tap方法"},
        {"title": "编写ADB清除应用数据脚本", "description": "编写Python代码，使用ADB命令清除指定应用的缓存和数据。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "ADB命令", "knowledge_point": "清除数据", "code_template": "import subprocess\n\n# 清除应用数据\n", "solution": "import subprocess\n\ndef clear_app_data(package_name):\n    # 清除应用数据\n    result = subprocess.run(\n        ['adb', 'shell', 'pm', 'clear', package_name],\n        capture_output=True, text=True\n    )\n    if 'Success' in result.stdout:\n        print(f'已清除 {package_name} 的数据')\n    else:\n        print(f'清除失败: {result.stderr}')\n    return 'Success' in result.stdout\n\ndef clear_app_cache(package_name):\n    result = subprocess.run(\n        ['adb', 'shell', 'pm', 'clear', '--cache-only', package_name],\n        capture_output=True, text=True\n    )\n    print(f'清除缓存: {result.stdout.strip()}')\n\nclear_app_data('com.example.app')", "hint": "使用pm clear命令清除应用数据"},
        {"title": "编写Appium页面滚动查找脚本", "description": "编写Python代码，实现滑动查找功能，通过滚动页面直到找到目标元素。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "Appium框架", "knowledge_point": "滚动查找", "code_template": "from appium.webdriver.common.by import By\nfrom selenium.common.exceptions import NoSuchElementException\n\n# 滚动查找元素\n", "solution": "from appium.webdriver.common.by import By\nfrom selenium.common.exceptions import NoSuchElementException\n\ndef scroll_and_find(driver, by, value, max_swipes=5):\n    for i in range(max_swipes):\n        try:\n            element = driver.find_element(by, value)\n            print(f'找到元素: {value}')\n            return element\n        except NoSuchElementException:\n            screen_size = driver.get_window_size()\n            width = screen_size['width']\n            height = screen_size['height']\n            driver.swipe(width//2, height*3//4, width//2, height//4, 800)\n            print(f'第 {i+1} 次滑动')\n    raise NoSuchElementException(f'滑动 {max_swipes} 次后未找到元素: {value}')\n\nelement = scroll_and_find(driver, By.XPATH, '//android.widget.TextView[@text=\"目标文本\"]')\nprint(element.text)", "hint": "循环滑动并尝试查找元素，捕获NoSuchElementException"},
        {"title": "编写ADB录屏脚本", "description": "编写Python代码，使用ADB命令录制设备屏幕视频。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "ADB命令", "knowledge_point": "录屏命令", "code_template": "import subprocess\nimport threading\nimport time\n\n# ADB录屏\n", "solution": "import subprocess\nimport threading\nimport time\n\ndef start_screenrecord(duration=10, output_path='screen_record.mp4'):\n    device_path = '/sdcard/record.mp4'\n    process = subprocess.Popen(\n        ['adb', 'shell', 'screenrecord', '--time-limit', str(duration), device_path],\n        stdout=subprocess.PIPE, stderr=subprocess.PIPE\n    )\n    print(f'开始录屏，时长 {duration} 秒')\n    process.wait()\n    subprocess.run(['adb', 'pull', device_path, output_path], check=True)\n    subprocess.run(['adb', 'shell', 'rm', device_path], check=True)\n    print(f'录屏已保存: {output_path}')\n\nstart_screenrecord(duration=15, output_path='test_video.mp4')", "hint": "使用screenrecord命令，time-limit参数设置时长"},
        {"title": "编写Appium多点触控脚本", "description": "编写Python代码，使用Appium实现多点触控操作，如双指缩放。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "Appium框架", "knowledge_point": "多点触控", "code_template": "from appium.webdriver.common.multi_action import MultiAction\nfrom appium.webdriver.common.touch_action import TouchAction\n\n# 双指缩放操作\n", "solution": "from appium.webdriver.common.multi_action import MultiAction\nfrom appium.webdriver.common.touch_action import TouchAction\n\ndef pinch_zoom(driver, zoom_in=True):\n    screen_size = driver.get_window_size()\n    center_x = screen_size['width'] // 2\n    center_y = screen_size['height'] // 2\n    offset = 100\n\n    action1 = TouchAction(driver)\n    action2 = TouchAction(driver)\n\n    if zoom_in:\n        action1.press(x=center_x - offset, y=center_y).move_to(x=center_x - offset*2, y=center_y).release()\n        action2.press(x=center_x + offset, y=center_y).move_to(x=center_x + offset*2, y=center_y).release()\n    else:\n        action1.press(x=center_x - offset*2, y=center_y).move_to(x=center_x - offset, y=center_y).release()\n        action2.press(x=center_x + offset*2, y=center_y).move_to(x=center_x + offset, y=center_y).release()\n\n    multi = MultiAction(driver)\n    multi.add(action1, action2)\n    multi.perform()\n    print(f'缩放操作完成: {\"放大\" if zoom_in else \"缩小\"}')\n\npinch_zoom(driver, zoom_in=True)", "hint": "使用MultiAction组合多个TouchAction"},
        {"title": "编写移动端CPU监控脚本", "description": "编写Python代码，使用ADB命令监控应用的CPU使用率。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "移动端性能测试", "knowledge_point": "CPU监控", "code_template": "import subprocess\nimport time\n\n# 监控CPU使用率\n", "solution": "import subprocess\nimport time\n\ndef monitor_cpu(package_name, duration=30, interval=2):\n    cpu_data = []\n    for i in range(0, duration, interval):\n        result = subprocess.run(\n            ['adb', 'shell', 'top', '-n', '1', '-b', '|', 'grep', package_name],\n            capture_output=True, text=True, shell=True\n        )\n        output = result.stdout.strip()\n        if output:\n            parts = output.split()\n            cpu_percent = parts[8] if len(parts) > 8 else '0'\n            cpu_data.append(float(cpu_percent))\n            print(f'时间 {i}s - CPU: {cpu_percent}%')\n        time.sleep(interval)\n    avg_cpu = sum(cpu_data) / len(cpu_data) if cpu_data else 0\n    print(f'平均CPU使用率: {avg_cpu:.1f}%')\n    return cpu_data\n\nmonitor_cpu('com.example.app', duration=20)", "hint": "使用top命令获取CPU信息"},
        {"title": "编写移动端内存监控脚本", "description": "编写Python代码，使用ADB命令监控应用的内存使用情况。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "移动端性能测试", "knowledge_point": "内存监控", "code_template": "import subprocess\nimport re\n\n# 监控内存使用\n", "solution": "import subprocess\nimport re\n\ndef monitor_memory(package_name):\n    result = subprocess.run(\n        ['adb', 'shell', 'dumpsys', 'meminfo', package_name],\n        capture_output=True, text=True\n    )\n    output = result.stdout\n    # 解析TOTAL行\n    match = re.search(r'TOTAL\s+(\d+)', output)\n    if match:\n        total_pss = int(match.group(1))\n        total_mb = total_pss / 1024\n        print(f'应用 {package_name} 内存使用: {total_mb:.1f} MB')\n        return total_mb\n    else:\n        print('无法解析内存信息')\n        return 0\n\ndef monitor_memory_over_time(package_name, count=5, interval=3):\n    import time\n    memory_data = []\n    for i in range(count):\n        mem = monitor_memory(package_name)\n        memory_data.append(mem)\n        if i < count - 1:\n            time.sleep(interval)\n    print(f'内存数据: {[f\"{m:.1f}MB\" for m in memory_data]}')\n    return memory_data\n\nmonitor_memory_over_time('com.example.app')", "hint": "使用dumpsys meminfo获取内存信息"},
        {"title": "编写Appium获取页面源码脚本", "description": "编写Python代码，使用Appium获取当前页面的XML源码并解析元素信息。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "元素定位", "knowledge_point": "页面源码", "code_template": "import xml.etree.ElementTree as ET\n\n# 获取页面源码并解析\n", "solution": "import xml.etree.ElementTree as ET\n\ndef get_page_source_and_parse(driver):\n    page_source = driver.page_source\n    root = ET.fromstring(page_source)\n    elements = []\n    for elem in root.iter():\n        text = elem.get('text', '')\n        resource_id = elem.get('resource-id', '')\n        class_name = elem.get('class', '')\n        if text or resource_id:\n            elements.append({\n                'text': text,\n                'resource_id': resource_id,\n                'class': class_name\n            })\n    print(f'页面共找到 {len(elements)} 个有效元素')\n    for e in elements[:10]:\n        print(f\"  text='{e['text']}' id='{e['resource_id']}' class='{e['class']}'\")\n    return elements\n\nget_page_source_and_parse(driver)", "hint": "使用driver.page_source获取XML，用ElementTree解析"},
        {"title": "编写ADB启动应用脚本", "description": "编写Python代码，使用ADB命令启动指定的Android应用。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "easy", "category": "ADB命令", "knowledge_point": "启动应用", "code_template": "import subprocess\n\n# 使用ADB启动应用\n", "solution": "import subprocess\n\ndef launch_app(package_name, activity):\n    component = f'{package_name}/{activity}'\n    result = subprocess.run(\n        ['adb', 'shell', 'am', 'start', '-n', component],\n        capture_output=True, text=True\n    )\n    if 'Error' in result.stderr:\n        print(f'启动失败: {result.stderr}')\n    else:\n        print(f'应用已启动: {component}')\n        print(result.stdout.strip())\n    return 'Error' not in result.stderr\n\ndef force_stop_app(package_name):\n    subprocess.run(['adb', 'shell', 'am', 'force-stop', package_name], check=True)\n    print(f'已强制停止: {package_name}')\n\nlaunch_app('com.example.app', '.MainActivity')", "hint": "使用am start -n命令启动Activity"},
        {"title": "编写Appium Toast检测脚本", "description": "编写Python代码，使用Appium检测Android Toast消息。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "元素定位", "knowledge_point": "Toast检测", "code_template": "from appium.webdriver.common.by import By\nfrom selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\n\n# 检测Toast消息\n", "solution": "from appium.webdriver.common.by import By\nfrom selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\n\ndef check_toast(driver, message, timeout=5):\n    try:\n        toast_xpath = f'//*[contains(@text,\"{message}\")]'\n        toast = WebDriverWait(driver, timeout).until(\n            EC.presence_of_element_located((By.XPATH, toast_xpath))\n        )\n        print(f'Toast已显示: {toast.text}')\n        return True\n    except Exception:\n        print(f'未找到Toast: {message}')\n        return False\n\ndef test_login_toast():\n    login_btn = driver.find_element(By.ID, 'com.example:id/login_btn')\n    login_btn.click()\n    result = check_toast(driver, '登录成功')\n    assert result, '未检测到登录成功Toast'\n\ntest_login_toast()", "hint": "Toast是Android特有的提示，使用xpath匹配文本"},
        {"title": "编写兼容性测试设备管理脚本", "description": "编写Python代码，实现一个设备管理器，用于管理多台测试设备信息。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "兼容性测试", "knowledge_point": "设备管理", "code_template": "# 设备管理器\n\nclass DeviceManager:\n    # 管理多台测试设备\n    pass", "solution": "class DeviceManager:\n    def __init__(self):\n        self.devices = []\n\n    def add_device(self, name, platform, version, resolution):\n        device = {\n            'name': name,\n            'platform': platform,\n            'version': version,\n            'resolution': resolution\n        }\n        self.devices.append(device)\n        print(f'添加设备: {name}')\n\n    def get_device(self, name):\n        for device in self.devices:\n            if device['name'] == name:\n                return device\n        return None\n\n    def get_devices_by_platform(self, platform):\n        return [d for d in self.devices if d['platform'] == platform]\n\n    def print_summary(self):\n        print(f'共 {len(self.devices)} 台设备:')\n        for d in self.devices:\n            print(f\"  {d['name']} - {d['platform']} {d['version']} {d['resolution']}\")\n\nmanager = DeviceManager()\nmanager.add_device('Pixel_6', 'Android', '13', '1080x2400')\nmanager.add_device('Samsung_S22', 'Android', '12', '1080x2340')\nmanager.add_device('iPhone_14', 'iOS', '16', '1170x2532')\nmanager.print_summary()", "hint": "使用字典存储设备信息，列表管理多台设备"},
        {"title": "编写Appium测试基类", "description": "编写Python代码，封装一个Appium测试基类，包含初始化、截图、关闭等通用方法。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "Appium框架", "knowledge_point": "测试基类", "code_template": "from appium import webdriver\nimport os\nfrom datetime import datetime\n\n# Appium测试基类\n\nclass AppiumBaseTest:\n    # 测试基类\n    pass", "solution": "from appium import webdriver\nimport os\nfrom datetime import datetime\n\nclass AppiumBaseTest:\n    def __init__(self, caps, server_url='http://localhost:4723/wd/hub'):\n        self.caps = caps\n        self.server_url = server_url\n        self.driver = None\n\n    def setup(self):\n        self.driver = webdriver.Remote(self.server_url, self.caps)\n        self.driver.implicitly_wait(10)\n        print('Driver初始化完成')\n\n    def teardown(self):\n        if self.driver:\n            self.driver.quit()\n            print('Driver已关闭')\n\n    def take_screenshot(self, name=None):\n        if name is None:\n            name = datetime.now().strftime('%Y%m%d_%H%M%S')\n        path = os.path.join('screenshots', f'{name}.png')\n        os.makedirs('screenshots', exist_ok=True)\n        self.driver.save_screenshot(path)\n        print(f'截图已保存: {path}')\n        return path\n\n    def get_page_source(self):\n        return self.driver.page_source\n\n    def __enter__(self):\n        self.setup()\n        return self\n\n    def __exit__(self, exc_type, exc_val, exc_tb):\n        self.teardown()\n        return False\n\n# 使用示例\ncaps = {'platformName': 'Android', 'deviceName': 'emulator', 'appPackage': 'com.example', 'appActivity': '.Main'}\nwith AppiumBaseTest(caps) as test:\n    test.take_screenshot('home_page')", "hint": "封装setup/teardown，支持with语句和截图功能"},
        {"title": "编写Appium并发测试脚本", "description": "编写Python代码，使用多线程在多台设备上并发执行Appium测试。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "Appium框架", "knowledge_point": "并发测试", "code_template": "from appium import webdriver\nimport threading\n\n# 并发测试\n", "solution": "from appium import webdriver\nimport threading\n\ndef run_test_on_device(device_caps, test_name):\n    driver = None\n    try:\n        driver = webdriver.Remote('http://localhost:4723/wd/hub', device_caps)\n        driver.implicitly_wait(10)\n        print(f'[{test_name}] 在 {device_caps[\"deviceName\"]} 上开始测试')\n        # 执行测试操作\n        page_source = driver.page_source\n        print(f'[{test_name}] 页面元素数: {len(page_source)}')\n        print(f'[{test_name}] 测试通过')\n    except Exception as e:\n        print(f'[{test_name}] 测试失败: {e}')\n    finally:\n        if driver:\n            driver.quit()\n\ndevices = [\n    {'platformName': 'Android', 'deviceName': 'emulator-5554', 'appPackage': 'com.example', 'appActivity': '.Main', 'udid': 'emulator-5554'},\n    {'platformName': 'Android', 'deviceName': 'emulator-5556', 'appPackage': 'com.example', 'appActivity': '.Main', 'udid': 'emulator-5556'},\n]\n\nthreads = []\nfor i, caps in enumerate(devices):\n    t = threading.Thread(target=run_test_on_device, args=(caps, f'Test_{i+1}'))\n    threads.append(t)\n    t.start()\n\nfor t in threads:\n    t.join()\nprint('所有设备测试完成')", "hint": "使用threading.Thread在多台设备上并行执行测试"},
        {"title": "编写移动端启动时间测试脚本", "description": "编写Python代码，使用ADB命令测量Android应用的冷启动时间。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "移动端性能测试", "knowledge_point": "启动时间", "code_template": "import subprocess\nimport re\nimport time\n\n# 测量应用启动时间\n", "solution": "import subprocess\nimport re\nimport time\n\ndef measure_cold_start(package_name, activity):\n    # 强制停止应用\n    subprocess.run(['adb', 'shell', 'am', 'force-stop', package_name], check=True)\n    time.sleep(2)\n    # 清除缓存\n    subprocess.run(['adb', 'shell', 'sync'], check=True)\n    subprocess.run(['adb', 'shell', 'echo', '3', '>', '/proc/sys/vm/drop_caches'], shell=True)\n    time.sleep(1)\n    # 启动应用并测量时间\n    component = f'{package_name}/{activity}'\n    result = subprocess.run(\n        ['adb', 'shell', 'am', 'start-W', '-n', component],\n        capture_output=True, text=True\n    )\n    # 解析启动时间\n    match = re.search(r'TotalTime:\\s*(\\d+)', result.stdout)\n    if match:\n        total_time = int(match.group(1))\n        print(f'冷启动时间: {total_time} ms')\n        return total_time\n    else:\n        print(f'无法解析启动时间: {result.stdout}')\n        return None\n\n# 多次测量取平均\ndef measure_average_start_time(package_name, activity, times=3):\n    results = []\n    for i in range(times):\n        print(f'第 {i+1} 次测量...')\n        t = measure_cold_start(package_name, activity)\n        if t:\n            results.append(t)\n        time.sleep(3)\n    if results:\n        avg = sum(results) / len(results)\n        print(f'平均冷启动时间: {avg:.0f} ms')\n    return results\n\nmeasure_average_start_time('com.example.app', '.MainActivity')", "hint": "使用am start -W获取启动时间，多次测量取平均值"},
        {"title": "编写Appium数据驱动测试脚本", "description": "编写Python代码，实现数据驱动的Appium登录测试，从数据列表读取测试数据。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "hard", "category": "Appium框架", "knowledge_point": "数据驱动", "code_template": "from appium.webdriver.common.by import By\nimport pytest\n\n# 数据驱动测试\n\ntest_data = [\n    {\"username\": \"admin\", \"password\": \"admin123\", \"expected\": \"登录成功\"},\n    {\"username\": \"\", \"password\": \"123456\", \"expected\": \"请输入用户名\"},\n    {\"username\": \"test\", \"password\": \"\", \"expected\": \"请输入密码\"},\n]\n", "solution": "from appium.webdriver.common.by import By\nimport pytest\n\ntest_data = [\n    {'username': 'admin', 'password': 'admin123', 'expected': '登录成功'},\n    {'username': '', 'password': '123456', 'expected': '请输入用户名'},\n    {'username': 'test', 'password': '', 'expected': '请输入密码'},\n]\n\ndef login_and_verify(driver, username, password, expected):\n    username_input = driver.find_element(By.ID, 'com.example:id/username')\n    password_input = driver.find_element(By.ID, 'com.example:id/password')\n    login_btn = driver.find_element(By.ID, 'com.example:id/login_btn')\n\n    username_input.clear()\n    username_input.send_keys(username)\n    password_input.clear()\n    password_input.send_keys(password)\n    login_btn.click()\n\n    import time\n    time.sleep(2)\n    page_source = driver.page_source\n    if expected in page_source:\n        print(f'验证通过: {expected}')\n        return True\n    else:\n        print(f'验证失败: 未找到 {expected}')\n        return False\n\n@pytest.mark.parametrize('case', test_data)\ndef test_login(driver, case):\n    result = login_and_verify(\n        driver,\n        case['username'],\n        case['password'],\n        case['expected']\n    )\n    assert result, f\"预期: {case['expected']}\"", "hint": "使用pytest.mark.parametrize参数化，遍历测试数据"},
        {"title": "编写ADB获取电池信息脚本", "description": "编写Python代码，使用ADB命令获取设备电池状态和电量信息。", "instructions": "请编写Python代码", "exercise_type": "code", "difficulty": "medium", "category": "ADB命令", "knowledge_point": "电池信息", "code_template": "import subprocess\nimport re\n\n# 获取电池信息\n", "solution": "import subprocess\nimport re\n\ndef get_battery_info():\n    result = subprocess.run(\n        ['adb', 'shell', 'dumpsys', 'battery'],\n        capture_output=True, text=True\n    )\n    output = result.stdout\n    info = {}\n    # 解析电量\n    match = re.search(r'level:\\s*(\\d+)', output)\n    if match:\n        info['level'] = int(match.group(1))\n    # 解析充电状态\n    match = re.search(r'status:\\s*(\\d+)', output)\n    if match:\n        status_map = {1: '未知', 2: '充电中', 3: '放电中', 4: '未充电', 5: '已满'}\n        info['status'] = status_map.get(int(match.group(1)), '未知')\n    # 解析温度\n    match = re.search(r'temperature:\\s*(\\d+)', output)\n    if match:\n        info['temperature'] = int(match.group(1)) / 10.0\n    print(f\"电量: {info.get('level', 'N/A')}%\")\n    print(f\"状态: {info.get('status', 'N/A')}\")\n    print(f\"温度: {info.get('temperature', 'N/A')} C\")\n    return info\n\nget_battery_info()", "hint": "使用dumpsys battery获取电池信息"},
